class Fib:
    def __init__(self, use_cache=False):
        self.use_cache = use_cache
        self.cache = {}

    def fib(self, n):
        # BUG: no memoization and too-deep recursion
        if n < 2:
            return n
        return self.fib(n - 1) + self.fib(n - 2)


def fib(n):
    return Fib().fib(n)


def main():
    # 1200 is well past default recursion limit
    r = fib(1200)
    print(r)


if __name__ == '__main__':
    main()
